def silver b
  b.split("").inject(0){|floor, i| floor += i == "(" ? 1 : -1 }  
end

def testSilver
  silver("(())") == 0 &&
  silver("(()(()(") == 3 &&
  silver("))(((((") == 3 &&
  silver(")())())") == -3 
end

def testGold
  gold(")") == 1 &&
  gold("()())") == 5
end


def gold b
  step = 1
  floor = 0
  b.split("").map{|i| i == "(" ? 1 : -1}.each.with_index { |dir, index|
    floor += dir
    return step if floor == -1
    step += 1
  }
  step
end

puts "Test for Silver: " + (testSilver ? "Passed ✓" : "Failed ✗")
puts "Silver: #{silver(BUILDING)}"
puts "Test for gold: " + (testGold ? "Passed ✓" : "Failed ✗")
puts "Gold: #{gold(BUILDING)}"